<template>
  <LTPages
      :title="'图片查看'"
      isNormal
  >
    <template v-slot:content>
      <div class="Docs-Body">
        <!--说明-->
        <div class="zhb-allnum-tip">
          <i class="icon zhb-iconfont zhb-icongantanhao"></i>
          <div style="width: 100%;">适应 视频监控平台的 图片查看。</div>
        </div>
        <!--1、基本用法-->
        <div class="zhb-title">基本用法</div>
        <div style="margin-bottom:15px;width: 300px;">
          <el-button @click="isLookPic = true">图片查看</el-button>
          <LTLookPic v-if="isLookPic" :url="LookPicUrl" @picClose="isLookPic = false, LookPicUrl = ''"></LTLookPic>
        </div>
        <!--2、代码示例-->
        <div class="zhb-title">代码示例</div>
        <!--template-->
        <codeCopy :code="mainCode" id="LTTooltip1" title="template"></codeCopy>
        <!--javaScript-->
        <codeCopy :code="jsCode" id="LTActionsForm2" title="javaScript"></codeCopy>
        <!--3、配置参数-->
        <div class="zhb-title">配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>

      </div>
    </template>
  </LTPages>
</template>

<script>
export default {
  data() {
    return {
      isLookPic: false,
      LookPicUrl: 'https://ftp.bmp.ovh/imgs/2021/06/18714484ed0bcedd.jpeg',
      mainCode: `<template>
        <el-button @click="isLookPic = true">图片查看</el-button>
        <LTLookPic v-if="isLookPic" :url="LookPicUrl" @picClose="isLookPic = false, LookPicUrl = ''"></LTLookPic>
</template>`,
      jsCode: `export default {
  data() {
    return {
      isLookPic: false,
      LookPicUrl: 'https://ftp.bmp.ovh/imgs/2021/06/18714484ed0bcedd.jpeg',
    }
  }
}`,
      // 配置参数
      tableData: [
        {
          text1:'url',
          text2:'图片地址',
          text3:'String',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'@picClose',
          text2:'关闭回调',
          text3:'Funtion',
          text4:'---',
          text5:'---',
          text6:'',
        }
      ],
    }
  }
}
</script>

